//! Variant D: McNally Cliff-Guided Compression
//! ==============================================
//!
//! Use the formal McNally Cliff criterion (σ₁/σ₂ ≥ 8) to decide which
//! layers are safe for low-rank compression. Only compress layers with
//! sharp cliffs in the spectral atlas.
//!
//! Theorem from CliffCapacityBridge.lean:
//!   cliff_capacity_friendly := (σ₁/σ₂ ≥ 8) ∧ (α ≤ 0.5)
//!
//! For Qwen-0.5B observed:
//!   L13: cliff=40×, α=0.40 → compress (75-50%)
//!   L14: cliff=38×, α=0.46 → compress (75-50%)
//!   L22: cliff=1.32×, α=0.83 → preserve full (no compression)
//!
//! For Phi-3-mini (projected):
//!   Expected cliff pattern (from architecture similarity):
//!   - Layers 0-10: no sharp cliff (white noise)
//!   - Layers 11-20: sharp cliff (brown/pink, Gnostic Valley)
//!   - Layers 21-31: cliff fades (final refinement)

const PHI3_INTERMEDIATE: usize = 8192;
const PHI3_LAYERS: usize = 32;

/// Projected McNally Cliff ratio for each Phi-3 layer
/// (estimated from Qwen-0.5B pattern + architectural scaling)
fn mcnally_cliff_ratio(layer: usize) -> f32 {
    // Empirical pattern from Qwen-0.5B + Llama-1B:
    // - Early layers (0-10): white noise, no cliff (ratio ≈ 1.1-1.5)
    // - Mid-pipeline (11-20): sharp cliff (ratio ≈ 40, 38, ...)
    // - Late layers (21-31): cliff degrades (ratio drops to 1.3-2)

    match layer {
        0..=10 => 1.2 + (layer as f32 * 0.02), // Gradually rising
        11..=12 => 35.0 - ((layer - 11) as f32 * 1.0), // Sharp (35, 34)
        13..=14 => 40.0 - ((layer - 13) as f32 * 2.0), // Peak (40, 38)
        15..=20 => 30.0 - ((layer - 15) as f32 * 4.5), // Declining (30, 25, 20, 15, 10, 5)
        21..=31 => 2.0 + (((31 - layer) as f32).max(0.0) * 0.1), // Fades out
        _ => 1.0,
    }
}

/// Is this layer's cliff sharp enough to compress?
/// Criterion: σ₁/σ₂ ≥ 8 (formal McNally Cliff threshold)
fn is_compressible_by_mcnally(layer: usize) -> bool {
    mcnally_cliff_ratio(layer) >= 8.0
}

/// Variant D: thin-banding — respect McNally Cliff, but don't waste speedup
/// Strategy:
///   - Gnostic Valley (cliff ≥ 8): compress to 50% (Variant B level, safe)
///   - Transition zones (5 ≤ cliff < 8): compress to 65% (moderate, less risk)
///   - Fragility/Late (cliff < 5): preserve full capacity (no cliff, no compression)
fn variant_d_intermediate_dim(layer: usize) -> usize {
    let cliff_ratio = mcnally_cliff_ratio(layer);

    if cliff_ratio >= 8.0 {
        // Gnostic Valley: safe for 50% compression
        (PHI3_INTERMEDIATE as f32 * 0.5).ceil() as usize
    } else if cliff_ratio >= 5.0 {
        // Transition: moderate 65% compression (avoid cliff while gaining speedup)
        (PHI3_INTERMEDIATE as f32 * 0.65).ceil() as usize
    } else {
        // Fragility/Late: preserve full capacity
        PHI3_INTERMEDIATE
    }
}

/// Expected speedup from Variant D (three-tier strategy)
fn estimate_speedup() -> f32 {
    let mut total_speedup = 1.0f32;

    for layer in 0..PHI3_LAYERS {
        let cliff_ratio = mcnally_cliff_ratio(layer);

        let layer_speedup = if cliff_ratio >= 8.0 {
            // 50% compression: ~1.54x speedup (Variant B level)
            1.54
        } else if cliff_ratio >= 5.0 {
            // 65% compression: ~1.35x speedup (between 75% and 50%)
            1.35
        } else {
            // No compression: baseline
            1.0
        };

        total_speedup *= layer_speedup;
    }

    // Geometric mean speedup across all layers
    total_speedup.powf(1.0 / PHI3_LAYERS as f32)
}

fn main() {
    println!("╔════════════════════════════════════════════════════════════════════╗");
    println!("║       Variant D: McNally Cliff-Guided Compression                  ║");
    println!("║  (Compress only layers with σ₁/σ₂ ≥ 8, per formal Lean theorem)    ║");
    println!("╚════════════════════════════════════════════════════════════════════╝\n");

    println!("MCNALLY CLIFF ANALYSIS:");
    println!("  Compressibility threshold: σ₁/σ₂ ≥ 8.0 (sharp cliff)\n");

    println!("  Layer │ Cliff Ratio │ Compressible? │ m (intermediate) │ Zone");
    println!("  ──────┼─────────────┼───────────────┼──────────────────┼──────────────");

    let mut compressible_layers = Vec::new();
    let mut preserved_layers = Vec::new();

    for layer in 0..PHI3_LAYERS {
        let cliff_ratio = mcnally_cliff_ratio(layer);
        let compressible = is_compressible_by_mcnally(layer);
        let m = variant_d_intermediate_dim(layer);

        let zone = if layer <= 10 {
            "early (white)"
        } else if layer <= 20 {
            "mid (valley)"
        } else {
            "late (fade)"
        };

        if layer % 4 == 0 || layer == PHI3_LAYERS - 1 {
            println!(
                "  {:>5} │ {:>11.2}x │ {:>13} │ {:>16} │ {}",
                layer,
                cliff_ratio,
                if compressible { "YES" } else { "NO " },
                m,
                zone
            );
        }

        if compressible {
            compressible_layers.push(layer);
        } else {
            preserved_layers.push(layer);
        }
    }

    println!("\nCOMPRESSION POLICY:");
    println!(
        "  Compressible layers (cliff ≥ 8×):  {:?}",
        compressible_layers
    );
    println!(
        "  Preserved layers (cliff < 8×):     {:?}",
        preserved_layers
    );

    println!("\nSPEEDUP ESTIMATE:");
    println!(
        "  Compressible:  {} layers × 1.54x speedup",
        compressible_layers.len()
    );
    println!(
        "  Preserved:     {} layers × 1.00x baseline",
        preserved_layers.len()
    );

    let speedup = estimate_speedup();
    println!("  ─────────────────────────────────────");
    println!("  Variant D expected speedup: {:.2}x", speedup);

    println!("\nCOMPARISON TO PREVIOUS VARIANTS:");
    println!("  Variant A (75% uniform):     0.3% loss  1.33x speedup");
    println!("  Variant B (50% uniform):     1.4% loss  1.54x speedup (avg)");
    println!("  Variant C (selective):      10.1% loss  1.81x speedup (CLIFF FAILURE)");
    println!(
        "  Variant D (McNally guided): ~0.8% loss  {:.2}x speedup ← PREDICTED",
        speedup
    );

    println!("\nFORMAL JUSTIFICATION:");
    println!("  This variant is justified by CliffCapacityBridge.lean:");
    println!("    cliff_capacity_friendly := (σ₁/σ₂ ≥ 8) ∧ (α ≤ 0.5)");
    println!("  Only compress layers where this predicate holds.");
    println!("  Late layers (22-31) fail the cliff antecedent → preserve full capacity");
    println!("  No phase-misalignment interference → no cascading loss");

    println!("\nACTION ITEMS:");
    println!("  1. Implement Variant D with this compression schedule");
    println!("  2. Run spectral-atlas on Phi-3-mini to measure actual cliff ratios");
    println!("  3. Validate MMLU loss on approved variants (expect ~0.8%)");
    println!("  4. Deploy if loss < 1.5% (within B's range)");

    println!("\nKEY INSIGHT:");
    println!("  The McNally Cliff formally separates:");
    println!("    - Gnostic Valley (brown/pink, α ≤ 0.5): compress freely");
    println!("    - Fragility zones (white, α > 0.5): preserve carefully");
    println!("  Variant C violates this by compressing non-cliff layers.");
    println!("  Variant D respects the cliff → expected to avoid the 10.1% cliff failure.");
}
